class SensitiveDataRedactor {
  static const List<String> _sensitiveKeys = [
    'password',
    'passwd',
    'secret',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'authorization',
    'api_key',
    'apikey',
    'api-key',
    'credit_card',
    'card_number',
    'cvv',
    'ssn',
    'social_security',
    'pin',
    'otp',
    'mfa_code',
    'private_key',
    'cookie',
    'session',
    'session_id',
    'csrf',
    'x-csrf-token',
    'bearer',
  ];

  static const List<RegExp> _sensitivePatterns = [];

  static final List<RegExp> _valuePatterns = [
    RegExp(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), // email
    RegExp(r'\b\d{3}-\d{2}-\d{4}\b'), // SSN
    RegExp(r'\b\d{13,19}\b'), // credit card numbers
    RegExp(r'eyJ[A-Za-z0-9_-]+\.eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+'), // JWT
  ];

  static const String _redactedPlaceholder = '[REDACTED]';

  /// Redact sensitive data from a map (e.g., headers, body, query params)
  static Map<String, dynamic> redactMap(Map<String, dynamic>? input) {
    if (input == null) return {};

    final redacted = <String, dynamic>{};
    for (final entry in input.entries) {
      redacted[entry.key] = _redactValue(entry.key, entry.value);
    }
    return redacted;
  }

  /// Redact sensitive headers specifically
  static Map<String, String> redactHeaders(Map<String, String>? headers) {
    if (headers == null) return {};

    final redacted = <String, String>{};
    for (final entry in headers.entries) {
      if (_isSensitiveKey(entry.key)) {
        redacted[entry.key] = _maskValue(entry.value);
      } else {
        redacted[entry.key] = entry.value;
      }
    }
    return redacted;
  }

  /// Redact a string that might contain sensitive patterns
  static String redactString(String input) {
    String result = input;
    for (final pattern in _valuePatterns) {
      result = result.replaceAll(pattern, _redactedPlaceholder);
    }
    return result;
  }

  static dynamic _redactValue(String key, dynamic value) {
    if (_isSensitiveKey(key)) {
      if (value is String) {
        return _maskValue(value);
      }
      return _redactedPlaceholder;
    }

    if (value is Map<String, dynamic>) {
      return redactMap(value);
    }

    if (value is List) {
      return value.map((item) {
        if (item is Map<String, dynamic>) {
          return redactMap(item);
        }
        return item;
      }).toList();
    }

    if (value is String) {
      return redactString(value);
    }

    return value;
  }

  static bool _isSensitiveKey(String key) {
    final lowerKey = key.toLowerCase().replaceAll(RegExp(r'[-_\s]'), '');
    return _sensitiveKeys.any((sensitive) {
      final lowerSensitive = sensitive.toLowerCase().replaceAll(RegExp(r'[-_\s]'), '');
      return lowerKey.contains(lowerSensitive);
    });
  }

  /// Show first and last few chars for debugging without full exposure
  static String _maskValue(String value) {
    if (value.length <= 6) return _redactedPlaceholder;
    final visibleChars = (value.length * 0.15).clamp(2, 4).toInt();
    return '${value.substring(0, visibleChars)}...$_redactedPlaceholder...${value.substring(value.length - visibleChars)}';
  }
}

// lib/logging/log_buffer.dart
import 'dart:collection';

class LogBuffer {
  final int maxSize;
  final Queue<LogEntry> _buffer = Queue<LogEntry>();

  LogBuffer({this.maxSize = 500});

  void add(LogEntry entry) {
    if (_buffer.length >= maxSize) {
      _buffer.removeFirst();
    }
    _buffer.add(entry);
  }

  List<LogEntry> getAll() => _buffer.toList();

  List<LogEntry> getByLevel(LogLevel minLevel) =>
      _buffer.where((e) => e.level.index >= minLevel.index).toList();

  List<LogEntry> getByCategory(String category) =>
      _buffer.where((e) => e.category == category).toList();

  List<LogEntry> getRecent(int count) {
    final all = _buffer.toList();
    return all.sublist((all.length - count).clamp(0, all.length));
  }

  void clear() => _buffer.clear();

  int get length => _buffer.length;
}

// lib/logging/log_sink.dart
import 'dart:convert';
import 'dart:io';

abstract class LogSink {
  Future<void> write(LogEntry entry);
  Future<void> flush();
}

class ConsoleLogSink extends LogSink {
  final LogLevel minLevel;

  ConsoleLogSink({this.minLevel = LogLevel.debug});

  @override
  Future<void> write(LogEntry entry) async {
    if (entry.level.index < minLevel.index) return;

    final prefix = _levelPrefix(entry.level);
    // Use debugPrint to avoid truncation of long messages
    debugPrint('$prefix ${entry.toString()}');

    if (entry.stackTrace != null && entry.level.index >= LogLevel.error.index) {
      debugPrint('  StackTrace: ${entry.stackTrace}');
    }
  }

  @override
  Future<void> flush() async {}

  String _levelPrefix(LogLevel level) {
    switch (level) {
      case LogLevel.debug:
        return '🔍';
      case LogLevel.info:
        return 'ℹ️';
      case LogLevel.warning:
        return '⚠️';
      case LogLevel.error:
        return '❌';
      case LogLevel.critical:
        return '🔥';
    }
  }
}

class FileLogSink extends LogSink {
  final String filePath;
  final LogLevel minLevel;
  final List<String> _pendingWrites = [];

  FileLogSink({required this.filePath, this.minLevel = LogLevel.info});

  @override
  Future<void> write(LogEntry entry) async {
    if (entry.level.index < minLevel.index) return;
    _pendingWrites.add(jsonEncode(entry.toJson()));

    if (_pendingWrites.length >= 20) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_pendingWrites.isEmpty) return;
    try {
      final file = File(filePath);
      final lines = _pendingWrites.join('\n') + '\n';
      await file.writeAsString(lines, mode: FileMode.append);
      _pendingWrites.clear();
    } catch (e) {
      debugPrint('FileLogSink flush error: $e');
    }
  }
}

/// Sends critical/error logs to a remote monitoring service
class RemoteLogSink extends LogSink {
  final String endpoint;
  final LogLevel minLevel;
  final List<LogEntry> _batch = [];
  final int batchSize;

  RemoteLogSink({
    required this.endpoint,
    this.minLevel = LogLevel.error,
    this.batchSize = 10,
  });

  @override
  Future<void> write(LogEntry entry) async {
    if (entry.level.index < minLevel.index) return;
    _batch.add(entry);

    if (_batch.length >= batchSize) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_batch.isEmpty) return;

    final entries = List<LogEntry>.from(_batch);
    _batch.clear();

    try {
      final client = HttpClient();
      final request = await client.postUrl(Uri.parse(endpoint));
      request.headers.set('Content-Type', 'application/json');
      request.write(jsonEncode({
        'logs': entries.map((e) => e.toJson()).toList(),
      }));
      final response = await request.close();
      await response.drain();
      client.close();
    } catch (e) {
      debugPrint('RemoteLogSink flush error: $e');
      // Re-add failed entries (up to limit)
      if (_batch.length + entries.length <= batchSize * 3) {
        _batch.addAll(entries);
      }
    }
  }
}

// lib/logging/app_logger.dart
import 'package:flutter/foundation.dart';

class AppLogger {
  static AppLogger? _instance;

  final List<LogSink> _sinks = [];
  final LogBuffer _buffer = LogBuffer(maxSize: 1000);
  late final LogLevel _minLevel;
  late final bool _isProduction;

  AppLogger._internal();

  static AppLogger get instance {
    _instance ??= AppLogger._internal();
    return _instance!;
  }

  /// Initialize with environment-appropriate settings
  void initialize({
    bool isProduction = false,
    List<LogSink>? sinks,
    String? remoteEndpoint,
    String? logFilePath,
  }) {
    _isProduction = isProduction;

    // In production: only info and above. In debug: everything.
    _minLevel = isProduction ? LogLevel.info : LogLevel.debug;

    _sinks.clear();

    if (sinks != null) {
      _sinks.addAll(sinks);
    } else {
      // Default sinks based on environment
      if (!isProduction) {
        _sinks.add(ConsoleLogSink(minLevel: LogLevel.debug));
      } else {
        // Production: limited console, file, and remote
        _sinks.add(ConsoleLogSink(minLevel: LogLevel.warning));
      }

      if (logFilePath != null) {
        _sinks.add(FileLogSink(
          filePath: logFilePath,
          minLevel: isProduction ? LogLevel.warning : LogLevel.info,
        ));
      }

      if (remoteEndpoint != null && isProduction) {
        _sinks.add(RemoteLogSink(
          endpoint: remoteEndpoint,
          minLevel: LogLevel.error,
        ));
      }
    }
  }

  void _log(
    LogLevel level,
    String category,
    String message, {
    Map<String, dynamic>? metadata,
    Object? error,
    StackTrace? stackTrace,
  }) {
    if (level.index < _minLevel.index) return;

    // Always redact metadata in production
    final safeMetadata = _isProduction
        ? (metadata != null ? SensitiveDataRedactor.redactMap(metadata) : null)
        : metadata; // In debug, show full data for local debugging only

    final entry = LogEntry(
      level: level,
      category: category,
      message: message,
      metadata: safeMetadata,
      errorMessage: error?.toString(),
      stackTrace: stackTrace?.toString(),
    );

    _buffer.add(entry);

    for (final sink in _sinks) {
      sink.write(entry);
    }
  }

  void debug(String category, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.debug, category, message, metadata: metadata);

  void info(String category, String message, {Map<String, dynamic>? metadata}) =>
      _log(LogLevel.info, category, message, metadata: metadata);

  void warning(String category, String message,
          {Map<String, dynamic>? metadata, Object? error}) =>
      _log(LogLevel.warning, category, message, metadata: metadata, error: error);

  void error(String category, String message,
          {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) =>
      _log(LogLevel.error, category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  void critical(String category, String message,
          {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) =>
      _log(LogLevel.critical, category, message,
          metadata: metadata, error: error, stackTrace: stackTrace);

  LogBuffer get buffer => _buffer;

  Future<void> flush() async {
    for (final sink in _sinks) {
      await sink.flush();
    }
  }

  /// Generate a diagnostic report (for crash reports / support tickets)
  Map<String, dynamic> generateDiagnosticReport() {
    final recentErrors = _buffer.getByLevel(LogLevel.error);
    final recentAll = _buffer.getRecent(50);

    return {
      'generated_at': DateTime.now().toIso8601String(),
      'recent_errors_count': recentErrors.length,
      'recent_errors': recentErrors.take(20).map((e) => e.toJson()).toList(),
      'recent_logs': recentAll.map((e) => e.toJson()).toList(),
      'total_buffered': _buffer.length,
    };
  }
}

